package policy

import (
	"context"
	"encoding/json"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// AuditVerdictType represents the verdict of a policy evaluation
type AuditVerdictType string

const (
	// VerdictAllow indicates the policy decision was to allow traffic
	VerdictAllow AuditVerdictType = "allow"
	// VerdictDeny indicates the policy decision was to deny traffic
	VerdictDeny AuditVerdictType = "deny"
	// VerdictUndecided indicates the policy decision was undecided
	VerdictUndecided AuditVerdictType = "undecided"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock.Mutex
	logger    logrus.FieldLogger
	logLevel  logrus.Level
	output    io.Writer
	useJSON   bool
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified configuration.
// If output is nil, logs will be sent to the default logger.
// If useJSON is true, logs will be formatted as JSON.
func NewPolicyAuditLogger(output io.Writer, logLevel logrus.Level, useJSON bool) *PolicyAuditLogger {
	logger := logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-audit")
	return &PolicyAuditLogger{
		logger:   logger,
		logLevel: logLevel,
		output:   output,
		useJSON:  useJSON,
	}
}

// LogDecision logs a policy decision with identity, policy, verdict, and reason.
// This is the primary method for recording policy evaluation outcomes.
func (pal *PolicyAuditLogger) LogDecision(identity string, policy string, verdict AuditVerdictType, reason string) {
	pal.Lock()
	defer pal.Unlock()

	// Build the structured log fields
	fields := logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict,
		"reason":           reason,
	}

	scopedLog := pal.logger.WithFields(fields)

	// Log based on verdict type
	switch verdict {
	case VerdictAllow:
		scopedLog.WithField("auditLevel", "decision").Info("Policy decision: ALLOW")
	case VerdictDeny:
		scopedLog.WithField("auditLevel", "decision").Warn("Policy decision: DENY")
	case VerdictUndecided:
		scopedLog.WithField("auditLevel", "decision").Debug("Policy decision: UNDECIDED")
	}

	// If JSON output is configured, also write structured JSON output
	if pal.useJSON && pal.output != nil {
		pal.writeJSONAuditLog(fields)
	}
}

// LogEvaluation logs a complete policy evaluation with context, selector cache, and result.
// This provides a detailed record of how a policy was evaluated.
func (pal *PolicyAuditLogger) LogEvaluation(
	ctx context.Context,
	policyKey string,
	selectorCache *SelectorCache,
	result interface{},
) {
	pal.Lock()
	defer pal.Unlock()

	// Build the structured log fields
	fields := logrus.Fields{
		"policyKey": policyKey,
		"result":    result,
	}

	// Add context information if available
	if ctx != nil {
		if deadline, ok := ctx.Deadline(); ok {
			fields["deadline"] = deadline
		}
	}

	// Add selector cache information
	if selectorCache != nil {
		model := selectorCache.GetModel()
		fields["selectorCacheSize"] = len(model)
	}

	scopedLog := pal.logger.WithFields(fields)
	scopedLog.WithField("auditLevel", "evaluation").Debug("Policy evaluation completed")

	// If JSON output is configured, also write structured JSON output
	if pal.useJSON && pal.output != nil {
		pal.writeJSONAuditLog(fields)
	}
}

// writeJSONAuditLog writes a JSON-formatted audit log entry to the configured output.
func (pal *PolicyAuditLogger) writeJSONAuditLog(fields logrus.Fields) {
	if pal.output == nil {
		return
	}

	auditEntry := map[string]interface{}{
		"level":  pal.logLevel.String(),
		"fields": fields,
	}

	if jsonBytes, err := json.Marshal(auditEntry); err == nil {
		pal.output.Write(jsonBytes)
		pal.output.Write([]byte("\n"))
	}
}

// SetLogLevel sets the log level for the audit logger.
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.Lock()
	defer pal.Unlock()
	pal.logLevel = level
}

// GetLogLevel returns the current log level of the audit logger.
func (pal *PolicyAuditLogger) GetLogLevel() logrus.Level {
	pal.Lock()
	defer pal.Unlock()
	return pal.logLevel
}

// LogIdentityDecision logs a decision for a specific identity numeric ID.
// This is a convenience method for logging decisions keyed by numeric identity.
func (pal *PolicyAuditLogger) LogIdentityDecision(
	numericID identity.NumericIdentity,
	policy string,
	verdict AuditVerdictType,
	reason string,
) {
	pal.LogDecision(numericID.String(), policy, verdict, reason)
}

