package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)
	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())
}

func TestLogDecision_Allow(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Log an allow decision
	logger.LogDecision("test-identity", "allow-all-policy", VerdictAllow, "default allow rule matched")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_Deny(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Log a deny decision
	logger.LogDecision("test-identity", "deny-policy", VerdictDeny, "explicit deny rule matched")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_Undecided(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Log an undecided decision
	logger.LogDecision("test-identity", "unknown-policy", VerdictUndecided, "no matching rule")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_ThreadSafety(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	// Run multiple concurrent logging operations
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(index int) {
			logger.LogDecision(
				"identity-"+string(rune(index)),
				"policy-"+string(rune(index)),
				VerdictAllow,
				"test reason",
			)
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	// Should complete without deadlock or panic
	require.NotNil(t, logger)
}

func TestLogEvaluation(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	ctx := context.Background()
	selectorCache := NewSelectorCache(nil)

	result := map[string]interface{}{
		"status": "completed",
	}

	logger.LogEvaluation(ctx, "test-policy-key", selectorCache, result)

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogEvaluation_WithContext(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	selectorCache := NewSelectorCache(nil)
	result := "evaluation-successful"

	logger.LogEvaluation(ctx, "context-aware-policy", selectorCache, result)

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogIdentityDecision(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	numericID := identity.NumericIdentity(1001)
	logger.LogIdentityDecision(numericID, "test-policy", VerdictAllow, "identity matched")

	// Should complete without error
	require.NotNil(t, logger)
}

func TestLogDecision_JSON(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, true)

	logger.LogDecision("json-test-identity", "json-policy", VerdictAllow, "json test reason")

	// Check that JSON was written (if JSON output is enabled)
	if buf.Len() > 0 {
		content := buf.Bytes()
		require.NotEmpty(t, content)

		// Try to unmarshal the JSON to verify it's valid
		var result map[string]interface{}
		err := json.Unmarshal(content, &result)
		require.NoError(t, err)
	}
}

func TestSetLogLevel(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, logger.GetLogLevel())
}

func TestGetLogLevel(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.DebugLevel, false)

	level := logger.GetLogLevel()
	require.Equal(t, logrus.DebugLevel, level)
}

func TestPolicyAuditLogger_NilOutput(t *testing.T) {
	// Create logger with nil output - should still work
	logger := NewPolicyAuditLogger(nil, logrus.InfoLevel, false)
	require.NotNil(t, logger)

	// Should handle nil output gracefully
	logger.LogDecision("test", "test", VerdictAllow, "test")
	logger.LogEvaluation(context.Background(), "test", nil, nil)

	require.NotNil(t, logger)
}

func TestAuditVerdictType_String(t *testing.T) {
	require.Equal(t, AuditVerdictType("allow"), VerdictAllow)
	require.Equal(t, AuditVerdictType("deny"), VerdictDeny)
	require.Equal(t, AuditVerdictType("undecided"), VerdictUndecided)
}

func TestLogEvaluation_NilSelectorCache(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	// Should handle nil SelectorCache gracefully
	logger.LogEvaluation(context.Background(), "policy-key", nil, "result")

	require.NotNil(t, logger)
}

func TestLogDecision_MultipleVerdicts(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	verdicts := []AuditVerdictType{VerdictAllow, VerdictDeny, VerdictUndecided}

	for _, verdict := range verdicts {
		logger.LogDecision("test-identity", "policy", verdict, "test reason")
	}

	require.NotNil(t, logger)
}

func TestLogIdentityDecision_MultipleIdentities(t *testing.T) {
	buf := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(buf, logrus.InfoLevel, false)

	for i := identity.NumericIdentity(1000); i < identity.NumericIdentity(1010); i++ {
		logger.LogIdentityDecision(i, "policy-"+i.String(), VerdictAllow, "test")
	}

	require.NotNil(t, logger)
}

